// Define a generic function isEven that takes a number n and returns a boolean indicating whether n is even.
function isEven<T>(n: T): boolean {
    if (typeof n === 'number') {
        return n % 2 === 0;
    } else {
        throw new Error('Input must be a number');
    }
}

