// Define a generic method is_even that takes a number n and returns a boolean indicating whether n is even.
class Solution:
    def is_even(self, n: any) -> bool:
        if isinstance(n, (int, float)):
            return n % 2 == 0
        else:
            raise ValueError('Input must be a number')
